    def test_models_use_source(self):
        """SQL models should use {{ source('...') }} for raw data."""
        found = False
        for fpath in self._find_sql_models():
            with open(fpath, "r", errors="ignore") as f:
                content = f.read()
            if "source(" in content or "{{ source" in content:
